122: // SelectableFields returns a field set that can be used for filter selection
123: func SelectableFields(obj *api.Secret) fields.Set {
124: 	objectMetaFieldsSet := generic.ObjectMetaFieldsSet(&obj.ObjectMeta, true)
125: 	secretSpecificFieldsSet := fields.Set{
126: 		"type": string(obj.Type),
127: 	}
128: 	return generic.MergeFieldsSets(objectMetaFieldsSet, secretSpecificFieldsSet)
129: }
